// Retrieve data from prior nodes
const topic = $('Execute Workflow Trigger').item.json.topic || '';
const serperData = $('HTTP - Serper News Search').item.json;
const youtubeData = $input.item.json;

// --- Process Serper News Results ---
const rawArticles = serperData.newsResults || [];
const articles = rawArticles.slice(0, 5).map(a => ({
  title:   a.title   || '',
  url:     a.link    || '',
  snippet: a.snippet || '',
  source:  a.source  || '',
  date:    a.date    || ''
}));

// --- Extract Numerical Stats via Regex ---
const allSnippets = articles.map(a => a.snippet).join(' ');
const statPatterns = [
  /\d+(?:\.\d+)?%/g,
  /\$[\d,]+(?:\.\d+)?(?:\s?[BMKTbmkt](?:illion|rillion)?)?/g,
  /\b\d{1,3}(?:,\d{3})+\s+[a-z]+/gi
];
const rawStats = [];
for (const pattern of statPatterns) {
  const found = allSnippets.match(pattern) || [];
  rawStats.push(...found);
}
const key_stats = [...new Set(rawStats)].slice(0, 8);

// --- Process YouTube Result ---
const ytItems = youtubeData.items || [];
const ytFirst = ytItems[0] || null;
const youtube = ytFirst ? {
  title:       ytFirst.snippet?.title        || '',
  url:         `https://www.youtube.com/watch?v=${ytFirst.id?.videoId || ''}`,
  description: (ytFirst.snippet?.description || '').substring(0, 200),
  channel:     ytFirst.snippet?.channelTitle || ''
} : null;

// --- Build enriched_context (~300 words, for GPT-4o injection) ---
const monthYear = new Date().toLocaleString('en-US', { month: 'long', year: 'numeric' });
const contextLines = [`Recent news on "${topic}" (as of ${monthYear}):`, ''];

articles.slice(0, 3).forEach(a => {
  if (a.snippet) {
    const words = a.snippet.trim().split(/\s+/);
    const truncated = words.slice(0, 80).join(' ') + (words.length > 80 ? '...' : '');
    contextLines.push(`Source: ${a.source || 'Unknown'} — ${truncated}`);
    contextLines.push('');
  }
});

if (key_stats.length > 0) {
  contextLines.push('Key statistics found in recent coverage:');
  key_stats.slice(0, 5).forEach(s => contextLines.push(`- ${s}`));
  contextLines.push('');
}

if (youtube && youtube.title) {
  contextLines.push(`Top YouTube resource: "${youtube.title}" by ${youtube.channel}`);
  contextLines.push(`URL: ${youtube.url}`);
}

const enriched_context = contextLines.join('\n').trim();

return { topic, articles, youtube, key_stats, enriched_context };
